Steps to reproduce against localstack:
1) stand up localstack via docker-compose up
```
version: '2.1'

services:
  localstack:
    image: localstack/localstack:0.8.7
    ports:
      - "4567-4583:4567-4583"
      - "8080:8080"
    environment:
      SERVICES: "lambda,sqs,sns,s3"
      LAMDA_EXECUTER: "docker"
      LAMBDA_REMOTE_DOCKER: "false"
      HOSTNAME: "danoaws"
      LOCALSTACK_HOSTNAME: "localhost"
      PORT_WEB_UI: "8080"
      DEBUG: "true"
    volumes:
      - ~/tmp/localstack:/tmp/localstack
      - /var/run/docker.sock:/var/run/docker.sock
```
